import{BidiServer}from"../bidiMapper/BidiMapper.js";import{MapperCdpConnection}from"../cdp/CdpConnection.js";import{LogType}from"../utils/log.js";import{BidiParser}from"./BidiParser.js";import{generatePage,log}from"./mapperTabPage.js";import{WindowBidiTransport,WindowCdpTransport}from"./Transport.js";generatePage();const mapperTabToServerTransport=new WindowBidiTransport,cdpTransport=new WindowCdpTransport,cdpConnection=new MapperCdpConnection(cdpTransport,log);async function runMapperInstance(r){console.log("Launching Mapper instance with selfTargetId:",r);const n=await BidiServer.createAndStart(mapperTabToServerTransport,cdpConnection,await cdpConnection.createBrowserSession(),r,new BidiParser,log);return log(LogType.debugInfo,"Mapper instance has been launched"),n}window.runMapperInstance=async r=>{await runMapperInstance(r)};